local function hideEngineWindow(name)
    local window = GUIManager:getWindowByName(name)
    if not window then
        return
    end
    window:SetXPosition({ 0, 6000 })
    window:SetVisible(false)
end

local function setTouchable(window, touchable)
    window:SetTouchable(touchable)
    local count = window:GetChildCount()
    if count == 0 then
        return
    end
    for index = 1, count do
        setTouchable(window:GetChildByIndex(index - 1), touchable)
    end
end

require "hall.ui.window.GUIPrivilegeStatusItem"

local UIMain = class("UIMain", IGUILayout)

function UIMain:onLoad()
    local btnLicense = self:getChildWindow("BedWarMain-License", GUIType.Button)
    btnLicense:registerEvent(GUIEvent.ButtonClick, function()
        GameAnalytics:design(1, { "H_License" })
        GUILicense:show()
        CommonPacketSender:sendPlayerOpenLicense()
    end)
    self.ivCheckInRedPoint = self:getChildWindow("BedWarMain-Check-In-Red-Point", GUIType.StaticImage)
    self.ivActivityRedPoint = self:getChildWindow("BedWarMain-Activity-Red-Point", GUIType.StaticImage)
    self.ivTreasureChallengeRedPoint = self:getChildWindow("BedWarMain-Treasure-Challenge-Red-Point", GUIType.StaticImage)
    self.ivLicenseRedPoint = self:getChildWindow("BedWarMain-License-Red-Point", GUIType.StaticImage)
    self.ivBlockShopPoint = self:getChildWindow("BedWarMain-BlockShop-RedPoint", GUIType.StaticImage)
    self.ivCheckInRedPoint:SetVisible(false)
    self.ivActivityRedPoint:SetVisible(false)
    self.ivTreasureChallengeRedPoint:SetVisible(false)
    self.ivLicenseRedPoint:SetVisible(false)
    self.ivBlockShopPoint:SetVisible(false)
    self:getChildWindow("BedWarMain-Check-In-Text"):SetText(Lang:getString("gui.check.in.txt"))
    self:getChildWindow("BedWarMain-Activity-Text"):SetText(Lang:getString("gui.activity.txt"))
    local btnCheckIn = self:getChildWindow("BedWarMain-Check-In")
    btnCheckIn:registerEvent(GUIEvent.ButtonClick, function()
        SoundUtil.clickUI()
        GUIDailySignIn:show()
    end)
    local btnActivity = self:getChildWindow("BedWarMain-Activity")
    btnActivity:registerEvent(GUIEvent.ButtonClick, function()
        SoundUtil.clickUI()
        GUIActivity:show()
    end)
    self:registerDataCallBack("PrivilegeStatus", function(data)
        self:onUpdatePrivilegeStatus(data)
    end, JsonBuilderProcessor)
    self:registerEvent(UpdateActivityRedPointEvent, function(type, visible)
        self:onActivityRedVisible(type, visible)
    end)
    self:registerEvent(UpdateDailySignInRedPointEvent, function(visible)
        self:onDailySignInRedVisible(visible)
    end)

    local TreasureChallengeBtn = self:getChildWindow("BedWarMain-Treasure-Challenge", GUIType.Button)
    TreasureChallengeBtn:registerEvent(GUIEvent.ButtonClick, function()
        self:onOpenTreasureChallenge()
    end)

    local CustomShopBtn = self:getChildWindow("BedWarMain-CustomShop", GUIType.Button)
    CustomShopBtn:registerEvent(GUIEvent.ButtonClick, function()
        GameAnalytics:design(1, { "H_customshop" })
        GUICustomShop:show(true)
    end)

    local btnBlockShop = self:getChildWindow("BedWarMain-BlockShop", GUIType.Button)
    btnBlockShop:registerEvent(GUIEvent.ButtonClick, function()
        GameAnalytics:design(1, { "H_blockshop" })
        GUIBlockShop:show()
    end)

    local btnRecharge = self:getChildWindow("BedWarMain-Recharge", GUIType.Button)
    btnRecharge:registerEvent(GUIEvent.ButtonClick, function()
        ReportUtil.reportClickFirstRecharge(GUISumRechargeLayout.currentId)
        GUISumRechargeLayout:show()
    end)

    self:registerDataCallBack("ShowSumRecharge", function(data)
        local id = data:getParam("Id")
        local config = SumRechargeConfig:getSumRecharge(id)
        if config then
            GUIManager:addShowQueue(GUISumRechargeLayout)
            btnRecharge:SetVisible(true)
        else
            btnRecharge:SetVisible(false)
        end
        if not Game:isEnableIndie() then
            GUIManager:addShowQueue(GUITreasureChallenge)
        end
    end, DataBuilderProcessor)

    self.siRedPoint = self:getChildWindow("BedWarMain-MenuList-RedPoint", GUIType.StaticImage)
    self.cbMenuList = self:getChildWindow("BedWarMain-MenuList-Switch", GUIType.CheckBox)
    self.cbMenuList:registerEvent(GUIEvent.CheckStateChanged, function()
        self:showMenuList(self.cbMenuList:GetChecked())
    end)

    self.redPointRecord = {}
    self.privilegeCards = {}
    self.task = nil

    self:setEngineUIStyle()
end

function UIMain:setEngineUIStyle()
    ClientHelper.putFloatPrefs("PoleControlMaxDistance", 65)
    ClientHelper.putFloatPrefs("MainControlKeyAlphaNormal", 1)
    ClientHelper.putFloatPrefs("MainControlKeyAlphaPress", 1)
    local ivPoleArrow = GUIManager:getWindowByName("Main-PoleControl-Arrow", GUIType.StaticImage)
    ivPoleArrow:SetImage("set:pole.json image:pole_arrow")
    local wMoveState = GUIManager:getWindowByName("Main-MoveState")
    wMoveState:SetArea(wMoveState:GetXPosition(), wMoveState:GetYPosition(), { 0, 70 }, { 0, 70 })
    local wJumControls = GUIManager:getWindowByName("Main-Jump-Controls")
    wJumControls:SetArea(wJumControls:GetXPosition(), wJumControls:GetYPosition(), { 0, 138 }, { 0, 377 })
    local btnSkillRelease = GUIManager:getWindowByName("Main-Skill-Release-btn", GUIType.Button)
    btnSkillRelease:SetNormalImage("set:bedwarsmall.json image:free_skill")
    btnSkillRelease:SetPushedImage("set:bedwarsmall.json image:free_skill")
    btnSkillRelease:SetArea(btnSkillRelease:GetXPosition(), btnSkillRelease:GetYPosition(), { 0, 120 }, { 0, 120 })
    local ivSneak = GUIManager:getWindowByName("Main-MoveState-Sneak", GUIType.StaticImage)
    ivSneak:SetImage("set:move_state.json image:sneak_circle")
    local btnFly = GUIManager:getWindowByName("Main-Fly", GUIType.Button)
    btnFly:SetNormalImage("set:bedwarsmall.json image:fly")
    btnFly:SetPushedImage("set:bedwarsmall.json image:fly")
    btnFly:SetArea(btnFly:GetXPosition(), btnFly:GetYPosition(), { 0, 70 }, { 0, 70 })
    hideEngineWindow("Main-Player-Exp")
    GUIManager:getWindowByName("Main-Chat-Message"):SetArea({ 0, 10 }, { 0, 130 }, { 0.38, 0 }, { 0.42, 0 })

    local bgWatch = GUIManager:getWindowByName("Main-Watch-Battle-Bg", GUIType.StaticImage)
    bgWatch:SetProperty("StretchOffset", "60 10 0 0")
    bgWatch:SetImage("set:bedwar_toolbar.json image:bg_onWatch")
    GUIManager:getWindowByName("Main-Watch-Battle-Tip"):SetHeight({ 0, 49 })
    GUIManager:getWindowByName("Main-Watch-Battle-Tip"):SetWidth({ 0, 250 })
    GUIManager:getWindowByName("Main-Watch-Battle-Text"):SetArea({ 0, 50 }, { 0, 0 }, { 1, -50 }, { 1, 0 })
    GUIManager:getWindowByName("Main-Watch-Battle-Text"):SetHorizontalAlignment(HorizontalAlignment.Left)
end

function UIMain:onActivityRedVisible(type, visible)
    if not self:isNeedLoad() then
        return
    end
    self.redPointRecord[type] = visible
    for _, record in pairs(self.redPointRecord) do
        if record then
            self.ivActivityRedPoint:SetVisible(true)
            return
        end
    end
    self.ivActivityRedPoint:SetVisible(false)
end

function UIMain:onDailySignInRedVisible(visible)
    self.ivCheckInRedPoint:SetVisible(visible)
end

function UIMain:onUpdatePrivilegeStatus(items)
    for _, item in pairs(items) do
        local privilege = self.privilegeCards[item.Id]
        if privilege == nil then
            local width = 70
            local count = self.llPrivilegeCards:GetChildCount()
            privilege = GUIPrivilegeStatusItem.new("PrivilegeStatusItem.json")
            privilege:setArea({ 1, count * (-20 - width) - 25 }, { 0, 0 }, { 0, width }, { 0, width })
            self.llPrivilegeCards:AddChildWindow(privilege.root)
        end
        privilege:initPrivilegeStatus(item.Icon, item.Time, item.Id)
        self.privilegeCards[item.Id] = privilege
    end
    if self.task ~= nil then
        LuaTimer:cancel(self.task)
    end
    self.task = LuaTimer:schedule(function()
        for _, privilege in pairs(self.privilegeCards) do
            privilege.time = privilege.time - 60
            privilege:updateTimeText()
        end
    end, 60 * 1000, 60 * 1000)
end

function UIMain:onOpenTreasureChallenge()
    GameAnalytics:design(1, { "H_Treasure" })
    GUITreasureChallenge:onDataChange(TreasureChallenge.rewardData)
    GUITreasureChallenge:show(true)
end

function UIMain:showMenuList(check)
    local layout = self:getChildWindow("BedWarMain-MenuList", GUIType.Layout)
    self.siRedPoint:SetVisible(false)
    LuaTimer:cancel(self.listKey or 0)
    if check then
        setTouchable(layout, false)
        self.listKey = LuaTimer:scheduleTimer(function()
            local curWidth = math.floor(layout:GetPixelSize().x)
            if curWidth == 0 then
                LuaTimer:cancel(self.listKey or 0)

            else
                if curWidth - 3 > 0 then
                    layout:SetWidth({ 0, curWidth - 20 })
                else
                    layout:SetWidth({ 0, 0 })
                end
            end
        end, 10)
    else
        setTouchable(layout, true)
        self.listKey = LuaTimer:scheduleTimer(function()
            local curWidth = math.floor(layout:GetPixelSize().x)
            if curWidth == 414 then
                LuaTimer:cancel(self.listKey or 0)
            else
                if curWidth + 3 < 354 then
                    layout:SetWidth({ 0, curWidth + 20 })
                else
                    layout:SetWidth({ 0, 414 })
                end
            end
        end, 10)
    end
end

function UIMain:hideList()

end

return UIMain